final:
module SR_latch (  
    input SR_S,  
    input R,  
    output reg Q,  
    output reg Qn  
);  
    always @ (SR_S or R) begin  
        if (SR_S && !R) begin  
            Q <= 1;  
            Qn <= 0;  
        end else if (!SR_S && R) begin  
            Q <= 0;  
            Qn <= 1;  
        end else if (SR_S && R) begin  
            // Invalid state, keep previous state
            Q <= Q;  
            Qn <= Qn;  
        end else begin  
            // Invalid state, keep previous state
            Q <= Q;  
            Qn <= Qn;  
        end  
    end  
endmodule
